Aero.module=new Vue({el:"#module",data:{loading:!0,items:[]},methods:{load:function(){fetch(Aero.baseUrl+"manager/api/module/list").then(function(e){return e.json()}).then(function(e){Aero.module.items=e.items}).catch(function(e){console.log("error:",e)})}},created:function(){this.load()},updated:function(){this.loading=!1}});